'use client'

import Link from 'next/link'
import { motion } from 'framer-motion'
import { ArrowRight } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { ProductCard } from '@/components/ui/ProductCard'
import { products } from '@/theme/tokens'

interface ProductsSectionProps {
  /** If true, show all 5 products (used on /products page). Default shows first 3. */
  showAll?: boolean
}

const containerVariants = {
  hidden: {},
  visible: {
    transition: {
      staggerChildren: 0.1,
    },
  },
}

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.5 } },
}

export function ProductsSection({ showAll = false }: ProductsSectionProps) {
  const displayed = showAll ? products : products.slice(0, 3)

  return (
    <section
      className="py-16 lg:py-24"
      id="products"
      aria-labelledby="products-heading"
      style={{ backgroundColor: '#f9fafb' }}
    >
      <div className="container mx-auto px-4 lg:px-8">
        {/* Section header */}
        <div className="text-center mb-12">
          <div className="flex items-center justify-center gap-3 mb-4">
            <div className="h-px w-12" style={{ backgroundColor: '#f3cf2d' }} />
            <span
              className="text-sm font-semibold uppercase tracking-widest"
              style={{ color: '#f3cf2d' }}
            >
              Our Products
            </span>
            <div className="h-px w-12" style={{ backgroundColor: '#f3cf2d' }} />
          </div>
          <h2
            id="products-heading"
            className="text-3xl sm:text-4xl font-bold"
            style={{ fontFamily: 'var(--font-heading)', color: '#061553' }}
          >
            Packaging Solutions
          </h2>
          <p className="mt-3 text-base max-w-xl mx-auto" style={{ color: '#666666' }}>
            High-quality industrial and packaging materials distributed reliably across sectors.
          </p>
        </div>

        {/* Product grid */}
        <motion.div
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, margin: '-50px' }}
          className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6"
        >
          {displayed.map((product) => (
            <motion.div key={product.id} variants={itemVariants}>
              <ProductCard
                id={product.id}
                name={product.name}
                category={product.category}
                image={product.image}
              />
            </motion.div>
          ))}
        </motion.div>

        {/* View all CTA — only shown when not displaying all */}
        {!showAll && (
          <div className="text-center mt-10">
            <Link href="/products">
              <Button
                size="lg"
                className="gap-2 font-semibold"
                style={{ backgroundColor: '#061553', color: 'white' }}
              >
                View All Products
                <ArrowRight className="h-5 w-5" aria-hidden="true" />
              </Button>
            </Link>
          </div>
        )}
      </div>
    </section>
  )
}
